#!/usr/bin/env node
// Generates src/lib/server/usStateBoundaries.generated.ts from Natural Earth's
// 110m admin-1 states/provinces GeoJSON. Run manually when the boundary source
// changes; the generated file is committed so runtime has no network dependency.

import { writeFile, mkdir } from 'node:fs/promises';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const SOURCE_URL =
	'https://raw.githubusercontent.com/nvkelso/natural-earth-vector/master/geojson/ne_110m_admin_1_states_provinces.geojson';
const OUT_PATH = join(
	dirname(fileURLToPath(import.meta.url)),
	'..',
	'src',
	'lib',
	'server',
	'usStateBoundaries.generated.ts'
);

// Target US state codes (ISO 3166-2:US, minus territories).
const US_STATE_CODES = new Set([
	'AL',
	'AK',
	'AZ',
	'AR',
	'CA',
	'CO',
	'CT',
	'DE',
	'DC',
	'FL',
	'GA',
	'HI',
	'ID',
	'IL',
	'IN',
	'IA',
	'KS',
	'KY',
	'LA',
	'ME',
	'MD',
	'MA',
	'MI',
	'MN',
	'MS',
	'MO',
	'MT',
	'NE',
	'NV',
	'NH',
	'NJ',
	'NM',
	'NY',
	'NC',
	'ND',
	'OH',
	'OK',
	'OR',
	'PA',
	'RI',
	'SC',
	'SD',
	'TN',
	'TX',
	'UT',
	'VT',
	'VA',
	'WA',
	'WV',
	'WI',
	'WY'
]);

function perpendicularDistance(point, lineStart, lineEnd) {
	const [x, y] = point;
	const [x1, y1] = lineStart;
	const [x2, y2] = lineEnd;
	const dx = x2 - x1;
	const dy = y2 - y1;
	if (dx === 0 && dy === 0) {
		const a = x - x1;
		const b = y - y1;
		return Math.sqrt(a * a + b * b);
	}
	const t = ((x - x1) * dx + (y - y1) * dy) / (dx * dx + dy * dy);
	const clamped = Math.max(0, Math.min(1, t));
	const projX = x1 + clamped * dx;
	const projY = y1 + clamped * dy;
	const a = x - projX;
	const b = y - projY;
	return Math.sqrt(a * a + b * b);
}

function rdp(points, epsilon) {
	if (points.length <= 2) return points.slice();
	let maxDist = 0;
	let index = 0;
	const first = points[0];
	const last = points[points.length - 1];
	for (let i = 1; i < points.length - 1; i++) {
		const d = perpendicularDistance(points[i], first, last);
		if (d > maxDist) {
			maxDist = d;
			index = i;
		}
	}
	if (maxDist > epsilon) {
		const left = rdp(points.slice(0, index + 1), epsilon);
		const right = rdp(points.slice(index), epsilon);
		return left.slice(0, -1).concat(right);
	}
	return [first, last];
}

function simplifyRing(ring, epsilon) {
	const closed =
		ring.length > 0 &&
		(ring[0][0] !== ring[ring.length - 1][0] || ring[0][1] !== ring[ring.length - 1][1]);
	const simplified = rdp(ring, epsilon);
	if (closed && simplified.length > 0) {
		const first = simplified[0];
		const last = simplified[simplified.length - 1];
		if (first[0] !== last[0] || first[1] !== last[1]) {
			simplified.push(first);
		}
	}
	return simplified;
}

function simplifyGeometry(geometry, epsilon) {
	if (!geometry) return null;
	if (geometry.type === 'Polygon') {
		return {
			type: 'Polygon',
			coordinates: geometry.coordinates.map((ring) => simplifyRing(ring, epsilon))
		};
	}
	if (geometry.type === 'MultiPolygon') {
		return {
			type: 'MultiPolygon',
			coordinates: geometry.coordinates.map((polygon) =>
				polygon.map((ring) => simplifyRing(ring, epsilon))
			)
		};
	}
	return null;
}

async function main() {
	const res = await fetch(SOURCE_URL);
	if (!res.ok) throw new Error(`Failed to fetch ${SOURCE_URL}: ${res.status}`);
	const geojson = await res.json();

	const entries = [];
	for (const feature of geojson.features) {
		const code = feature.properties?.postal;
		if (!code || !US_STATE_CODES.has(code)) continue;
		const simplified = simplifyGeometry(feature.geometry, 0.02);
		if (!simplified) continue;
		entries.push({ code, geometry: simplified });
	}

	// Sort deterministically.
	entries.sort((a, b) => a.code.localeCompare(b.code));

	if (entries.length !== US_STATE_CODES.size) {
		throw new Error(
			`Expected ${US_STATE_CODES.size} US states/DC but found ${entries.length}`
		);
	}

	const serialized = JSON.stringify(entries);
	const ts = `// Generated by scripts/generate-us-state-boundaries.mjs — do not edit manually.
// Source: Natural Earth 110m admin-1 states/provinces (public domain).
// Simplified with Ramer-Douglas-Peucker, epsilon = 0.02 degrees.

export type StateBoundary = {
	code: string;
	geometry: { type: 'Polygon' | 'MultiPolygon'; coordinates: number[][][] | number[][][][] };
};

export const US_STATE_BOUNDARIES: StateBoundary[] = ${serialized};
`;

	await mkdir(dirname(OUT_PATH), { recursive: true });
	await writeFile(OUT_PATH, ts, 'utf8');
	console.log(`Wrote ${OUT_PATH} (${entries.length} states, ${ts.length} bytes)`);
}

main().catch((err) => {
	console.error(err);
	process.exit(1);
});
